import React, { useState, useEffect } from "react";
import TripForm from "./components/TripForm";
import StationForm from "./components/StationForm";
import TrainForm from "./components/TrainForm";
import RouteForm from "./components/RouteForm";

function App() {
  const [stations, setStations] = useState([]);
  const [trains, setTrains] = useState([]);
  const [routes, setRoutes] = useState([]);
  const [trips, setTrips] = useState([]);

  // ==== ЗАГРУЗКА ДАННЫХ ИЗ LOCALSTORAGE ИЛИ СЕРВЕРА ====
  useEffect(() => {
    const s = localStorage.getItem("stations");
    const t = localStorage.getItem("trains");
    const r = localStorage.getItem("routes");
    const tr = localStorage.getItem("trips");

    if (s) setStations(JSON.parse(s));
    else fetch("http://localhost:5050/stations").then(r => r.json()).then(setStations);

    if (t) setTrains(JSON.parse(t));
    else fetch("http://localhost:5050/trains").then(r => r.json()).then(setTrains);

    if (r) setRoutes(JSON.parse(r));
    else fetch("http://localhost:5050/routes").then(r => r.json()).then(setRoutes);

    if (tr) setTrips(JSON.parse(tr));
    else fetch("http://localhost:5050/trips").then(r => r.json()).then(setTrips);
  }, []);

  // ==== СОХРАНЕНИЕ В LOCALSTORAGE ПРИ ИЗМЕНЕНИИ ====
  useEffect(() => localStorage.setItem("stations", JSON.stringify(stations)), [stations]);
  useEffect(() => localStorage.setItem("trains", JSON.stringify(trains)), [trains]);
  useEffect(() => localStorage.setItem("routes", JSON.stringify(routes)), [routes]);
  useEffect(() => localStorage.setItem("trips", JSON.stringify(trips)), [trips]);

  // ===== ДОБАВЛЕНИЕ =====
  const handleNewStation = s => setStations(prev => [...prev, s]);
  const handleNewTrain = t => setTrains(prev => [...prev, t]);
  const handleNewRoute = r => setRoutes(prev => [...prev, r]);
  const handleNewTrip = t => setTrips(prev => [...prev, t]);

  // ===== УДАЛЕНИЕ =====
  const deleteStation = async (id) => {
    await fetch(`http://localhost:5050/stations/${id}`, { method: "DELETE" });
    setStations(prev => prev.filter(s => s.id !== id));
  };

  const deleteTrain = async (id) => {
    await fetch(`http://localhost:5050/trains/${id}`, { method: "DELETE" });
    setTrains(prev => prev.filter(t => t.id !== id));
  };

  const deleteRoute = async (id) => {
    await fetch(`http://localhost:5050/routes/${id}`, { method: "DELETE" });
    setRoutes(prev => prev.filter(r => r.id !== id));
    setTrips(prev => prev.filter(t => t.route_id !== id));
  };

  const deleteTrip = async (id) => {
    await fetch(`http://localhost:5050/trips/${id}`, { method: "DELETE" });
    setTrips(prev => prev.filter(t => t.id !== id));
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>🚆 Транспортная система</h1>

      {/* СТАНЦИИ */}
      <h2>Станции</h2>
      <StationForm onNewStation={handleNewStation} />
      {stations.map(s => (
        <div key={s.id}>
          {s.name} 
          <button onClick={() => deleteStation(s.id)}>❌</button>
        </div>
      ))}

      {/* ПОЕЗДА */}
      <h2>Поезда</h2>
      <TrainForm onNewTrain={handleNewTrain} />
      {trains.map(t => (
        <div key={t.id}>
          🚆 {t.number}
          <button onClick={() => deleteTrain(t.id)}>❌</button>
        </div>
      ))}

      {/* МАРШРУТЫ */}
      <h2>Маршруты</h2>
      <RouteForm stations={stations} onNewRoute={handleNewRoute} />
      {routes.map(r => (
        <div key={r.id}>
          {r.departure} → {r.arrival}
          {r.stops && r.stops.length > 0
            ? ` (остановки: ${r.stops.join(", ")})`
            : " (без остановок)"}
          <button onClick={() => deleteRoute(r.id)}>❌</button>
        </div>
      ))}

      {/* РЕЙСЫ */}
      <h2>Рейсы</h2>
      <TripForm routes={routes} trains={trains} onNewTrip={handleNewTrip} />

      <table border="1" cellPadding="5" style={{ marginTop: "10px", borderCollapse: "collapse" }}>
        <thead>
          <tr>
            <th>ID</th>
            <th>Поезд</th>
            <th>Маршрут</th>
            <th>Отправление</th>
            <th>Прибытие</th>
            <th>Удалить</th>
          </tr>
        </thead>
        <tbody>
          {trips.map(t => {
            const route = routes.find(r => r.id === t.route_id);
            const train = trains.find(tr => tr.id === t.train_id);

            return (
              <tr key={t.id}>
                <td>{t.id}</td>
                <td>{train?.number || "—"}</td>
                <td>{route ? `${route.departure} → ${route.arrival}` : "—"}</td>
                <td>{t.departure_time}</td>
                <td>{t.arrival_time}</td>
                <td>
                  <button onClick={() => deleteTrip(t.id)}>❌</button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

export default App;
